scwin.grid_excel = async function () {
  let option = {
    "fileName": "코일 입출고 내역.xlsx",
    "sheetName": "코일 입출고 내역"
  };
  grd_excel.setDownOpts(option);
  if (ds_master.getTotalRow() != 0) {
    if (await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?")) {
      $c.data.downloadGridViewExcel($p, gr_master, option);
    }
  } else {
    $c.win.alert($p, MSG_CM_WRN_002);
  }
};

//-------------------------------------------------------------------------
