//-------------------------------------------------------------------------
scwin.uploadExcel = async function () {
  if (grd_excel.getUpExt() == "1") {
    let options = {
      "fileName": "gridDataUpload.csv",
      "status": "C",
      "header": 1,
      "type": "1",
      "startRowIndex": 0,
      "footerExist": 0
    };
    await $c.data.uploadGridViewCSV($p, gr_master, options);
  } else {
    let options = {
      "fileName": "gridDataUpload.xlsx",
      "status": "C",
      "headerExist": 1,
      "type": "1",
      "startRowIndex": 0
    };
    await $c.data.uploadGridViewExcel($p, gr_master, options);
  }
};

