//-------------------------------------------------------------------------
// 그리드 편집시 
//-------------------------------------------------------------------------
scwin.gr_master_onafteredit = function (rowIndex, columnIndex, value) {
  var pAutoClostTF = "T";
  let row = rowIndex;
  let colid = gr_master.getColumnID(columnIndex);
  if (value == scwin.oldDataCd) {
    return;
  }
  switch (colid) {
    case "clntNm":
      //화주 조회 팝업			
      if (ds_master.getCellData(row, colid).length == 0) {
        if (ds_master.getCellData(row, "clntNo").length !== 0) {
          ds_master.setCellData(row, "clntNo", "");
        } else {
          return;
        }
      } else {
        scwin.f_OpenGridPopUp(6, '', ds_master.getCellData(row, colid), 'T', 'T', pAutoClostTF, value, "onafteredit");
      }
      break;
    case "cvsslMgntNo":
      //본선관리번호 조회 팝업
      if (ds_master.getCellData(row, colid).length == 0) return;
      scwin.f_OpenGridPopUp(9, ds_master.getCellData(row, colid), '', 'T', 'T', pAutoClostTF, value, "onafteredit");
      break;
    case "vsslNm":
      //LINE 조회 팝업
      if (ds_master.getCellData(row, colid).length == 0) {
        if (ds_master.getCellData(row, "vsslCd").length !== 0) {
          ds_master.setCellData(row, "vsslCd", "");
        } else {
          return;
        }
      } else {
        scwin.f_OpenGridPopUp(11, '', ds_master.getCellData(row, colid), 'T', 'T', pAutoClostTF, value, "onafteredit");
      }
      break;
    case "wrkPlNm":
      if (ds_master.getCellData(row, colid).length == 0) {
        if (ds_master.getCellData(row, "wrkPlCd").length !== 0) {
          ds_master.setCellData(row, "wrkPlCd", "");
        } else {
          return;
        }
      } else {
        scwin.f_OpenGridPopUp(10, '', ds_master.getCellData(row, colid), 'T', 'T', pAutoClostTF, value, "onafteredit");
      }
      break;
    case "shippingListNo":
      if (ds_master.getCellData(row, colid).length == 0) return;
      scwin.f_openShippingListMgntNoPopUp(row);
      break;
    case "pdaClntNm":
      if (ds_master.getCellData(row, colid).length == 0) {
        if (ds_master.getCellData(row, "pdaClntNo").length !== 0) {
          ds_master.setCellData(row, "pdaClntNo", "");
        } else {
          return;
        }
      } else {
        scwin.f_OpenGridPopUp(12, '', ds_master.getCellData(row, colid), 'T', 'T', pAutoClostTF, value, "onafteredit");
      }
      break;
    case "carNm":
      if (ds_master.getCellData(row, colid).length == 0) {
        if (ds_master.getCellData(row, "vehclNo").length !== 0) {
          ds_master.setCellData(row, "vehclNo", "");
        } else {
          return;
        }
      } else {
        scwin.f_OpenGridPopUp(13, '', ds_master.getCellData(row, colid), 'T', 'T', pAutoClostTF, value, "onafteredit");
      }
      break;
    case "dptWrkPlNm":
      if (ds_master.getCellData(row, colid).length == 0) {
        if (ds_master.getCellData(row, "dptWrkPlCd").length !== 0) {
          ds_master.setCellData(row, "dptWrkPlCd", "");
        } else {
          return;
        }
      } else {
        scwin.f_OpenGridPopUp(14, '', ds_master.getCellData(row, colid), 'T', 'T', pAutoClostTF, value, "onafteredit");
      }
      break;
    case "arvWrkPlNm":
      if (ds_master.getCellData(row, colid).length == 0) {
        if (ds_master.getCellData(row, "arvWrkPlCd").length !== 0) {
          ds_master.setCellData(row, "arvWrkPlCd", "");
        } else {
          return;
        }
      } else {
        scwin.f_OpenGridPopUp(15, '', ds_master.getCellData(row, colid), 'T', 'T', pAutoClostTF, value, "onafteredit");
      }
      break;
    case "coilWidth":
      if (value == "") {
        ds_master.setCellData(rowIndex, "coilWidth", 0.00);
      }
      break;
    case "coilLength":
      if (value == "") {
        ds_master.setCellData(rowIndex, "coilLength", 0);
      }
      break;
    case "netWt":
      if (value == "") {
        ds_master.setCellData(rowIndex, "netWt", 0);
      }
      break;
    case "grossWt":
      if (value == "") {
        ds_master.setCellData(rowIndex, "grossWt", 0);
      }
      break;
    default:
      break;
  }
};

