//-------------------------------------------------------------------------
scwin.btn_withDraw_onClick = async function (e) {
  let j = 0;
  for (i = 0; i < ds_master.getTotalRow(); i++) {
    if (ds_master.getCellData(i, 'chk') == "T" && ds_master.getCellData(i, 'ioClsCd') == "I") {
      j = j + 1;
    }
  }
  if (j < 1) {
    await $c.win.alert($p, "1개 이상의 입고 데이터를 선택하셔야 출고할 수 있습니다.");
    return false;
  } else {
    let k = 0;
    ds_out.removeAll();
    if (ica_etDt.getValue() == "" || ica_etDt.getValue() == null) {
      await $c.win.alert($p, '출고예정일자를 입력하세요.');
      ica_etDt.focus();
      return;
    }
    let ret = await $c.win.confirm($p, "선택된 입고 데이터를 출고하시겠습니까?");
    if (ret) {
      for (i = 0; i < ds_master.getTotalRow(); i++) {
        if (ds_master.getCellData(i, "chk") == "T" && ds_master.getCellData(i, "ioClsCd") == "O") {
          await $c.win.alert($p, "선택한 코일 [" + ds_master.getCellData(i, "rollNo") + "] 은(는) 출고건입니다.");
          return;
        }
        if (ds_master.getCellData(i, "chk") == "T" && ds_master.getCellData(i, "ioClsCd") == "I") {
          k++;

          // 출고할 코일의 첫 행에만 정보를 입력해도 
          // 나머지 출고건에 대해서 자동으로 
          // 출고구분코드,운송업체, 출발지, 도착지가 셋팅되어 저장되도록 하는 로직
          // 단, 출고시 첫 행에는 필수정보가 모두 입력되어야한다. 

          if (k == 1) {
            if (ds_master.getCellData(i, "transClsCd") == "") {
              await $c.win.alert($p, "출고 시에 출고구분코드는 필수값입니다.");
              gr_master.setFocusedCell(i, "transClsCd");
              return;
            }
            if (ds_master.getCellData(i, "transClsCd") == "2") {
              ds_master.setCellData(i, "dptWrkPlCd", "6P101");
              ds_master.setCellData(i, "dptWrkPlNm", "울산항");
              ds_master.setCellData(i, "arvWrkPlCd", "6Z22");
              ds_master.setCellData(i, "arvWrkPlNm", "울산현대자동차");
            }
            if (ds_master.getCellData(i, "pdaClntNo") == "" && ds_master.getCellData(i, "transClsCd") != "1") {
              await $c.win.alert($p, "출고 시에 운송업체는 필수값입니다.");
              gr_master.setFocusedCell(i, "pdaClntNm");
              return;
            }
            if (ds_master.getCellData(i, "transClsCd") != "1" && ds_master.getCellData(i, "dptWrkPlCd") == "" || ds_master.getCellData(i, "dptWrkPlNm") == "" && ds_master.getCellData(i, "transClsCd") != "1") {
              await $c.win.alert($p, "출고 시에 출발지는 필수값입니다.");
              gr_master.setFocusedCell(i, "dptWrkPlNm");
              return;
            }
            if (ds_master.getCellData(i, "transClsCd") != "1" && ds_master.getCellData(i, "arvWrkPlCd") == "" || ds_master.getCellData(i, "arvWrkPlNm") == "" && ds_master.getCellData(i, "transClsCd") != "1") {
              await $c.win.alert($p, "출고 시에 도착지는 필수값입니다.");
              gr_master.setFocusedCell(i, "arvWrkPlNm");
              return;
            }
            if (ds_master.getCellData(i, "cvsslMgntNo") == "") {
              await $c.win.alert($p, "출고 시에 본선관리번호는 필수값입니다.");
              gr_master.setFocusedCell(i, "cvsslMgntNo");
              return;
            }
          }
          let transClsCd1 = ds_master.getCellData(i, "transClsCd");
          let pdaClntNo1 = ds_master.getCellData(i, "pdaClntNo");
          let pdaClntNm1 = ds_master.getCellData(i, "pdaClntNm");
          let dptWrkPlCd1 = ds_master.getCellData(i, "dptWrkPlCd");
          let dptWrkPlNm1 = ds_master.getCellData(i, "dptWrkPlNm");
          let arvWrkPlCd1 = ds_master.getCellData(i, "arvWrkPlCd");
          let arvWrkPlNm1 = ds_master.getCellData(i, "arvWrkPlNm");
          if (ds_master.getCellData(i, "transClsCd") == "") {
            ds_master.setCellData(i, "transClsCd", transClsCd1);
          } else if (ds_master.getCellData(i, "transClsCd") != transClsCd1) {
            await $c.win.alert($p, "출고구분은 출고할 코일 중 첫 행에만 선택해 주세요.");
            return;
          }
          if (ds_master.getCellData(i, "pdaClntNo") == "") {
            ds_master.setCellData(i, "pdaClntNo", pdaClntNo1);
            ds_master.setCellData(i, "pdaClntNm", pdaClntNm1);
          } else if (ds_master.getCellData(i, "pdaClntNo") != pdaClntNo1) {
            await $c.win.alert($p, "운송업체는 출고할 코일 중 첫 행에만 선택해 주세요.");
            return;
          }
          if (ds_master.getCellData(i, "dptWrkPlCd") == "") {
            ds_master.setCellData(i, "dptWrkPlCd", dptWrkPlCd1);
            ds_master.setCellData(i, "dptWrkPlNm", dptWrkPlNm1);
          } else if (ds_master.getCellData(i, "dptWrkPlCd") != dptWrkPlCd1) {
            await $c.win.alert($p, "출발지는 출고할 코일 중 첫 행에만 선택해 주세요.");
            return;
          }
          if (ds_master.getCellData(i, "arvWrkPlCd") == "") {
            ds_master.setCellData(i, "arvWrkPlCd", arvWrkPlCd1);
            ds_master.setCellData(i, "arvWrkPlNm", arvWrkPlNm1);
          } else if (ds_master.getCellData(i, "arvWrkPlCd") != arvWrkPlCd1) {
            await $c.win.alert($p, "도착지는 출고할 코일 중 첫 행에만 선택해 주세요.");
            return;
          }
          let copyData = ds_master.getRowData(i);
          ds_out.setRowData(i, copyData);
          ds_out.setCellData(i, "chk", "");
          ds_out.setCellData(i, "bilgYn", "N");
          ds_out.setCellData(i, "ioClsCd", "O");
          ds_out.setCellData(i, "lobranCd", scwin.loUpperLobranCd);
          ds_out.setCellData(i, "rsltsDt", scwin.vCurDate);
          ds_out.setCellData(i, "etDt", ica_etDt.getValue());
          if (ds_master.getCellData(i, "mgntClsCd") == "T") {
            ds_out.setCellData(i, "transClsCd", "2");
            ds_out.setCellData(i, "dptWrkPlCd", "6P101");
            ds_out.setCellData(i, "arvWrkPlCd", "6Z22");
          }
        }
      }
      for (j = 0; j < ds_out.getTotalRow(); j++) {
        let row = ds_master.getRowCount();
        let copyData2 = ds_out.getRowData(j);
        ds_master.setRowData(row, copyData2);
        ds_master.setCellData(row, "ioClsCd", "O");
        ds_master.setCellData(row, "etDt", ica_etDt.getValue());
        ds_master.setCellData(row, "chk", "");
      }
      sbm_withdraw.userData1 = "noError";
      let e = await $c.sbm.execute($p, sbm_withdraw);
      if (e.responseJSON.resultDataSet[0].Code == -1) {
        // error 
        await $c.win.alert($p, e.responseJSON.resultDataSet[1].Msg);
        $c.data.undoAll($p, ds_master);
      }
      scwin.sbm_withdraw_submitDone(e);
    }
    spa_totalRows.setValue(ds_master.getTotalRow());
  }
};

