//-------------------------------------------------------------------------
scwin.sbm_master_submitDone = function (e) {
  try {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    $c.win.alert($p, MSG_CM_INF_001);
    scwin.btn_retrieve_onClick();
    scwin.excelYn = "0";
    ica_etDt.setValue("");
    ica_rsltsStdDt.setValue("");
  } catch (e) {
    console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
  }
};

//-------------------------------------------------------------------------
// 그리드 셀 클릭시
//-------------------------------------------------------------------------
scwin.gr_master_onClick = function (rowIndex, columnIndex, columnId) {
  if (rowIndex >= 0) {
    scwin.f_CheckBilgYn(rowIndex, columnId, "OnClick");
  }
};

//-------------------------------------------------------------------------
// 청구처리 확인 => 청구처리가 되었다면 수정 불가
//-------------------------------------------------------------------------
scwin.f_CheckBilgYn = function (row, colId, callType) {
  let rollNo = ds_master.getCellData(row, colId);
  for (i = 0; i < ds_master.getTotalRow(); i++) {
    if (rollNo == ds_master.getCellData(i, "rollNo") && ds_master.getCellData(i, "bilgYn") == "Y") {
      if (callType == "OnColumnPosChanged") {
        $c.win.alert($p, "청구처리가 된 화물입니다. <br> 수정이 불가능합니다.");
      }
      gr_master.setRowReadOnly(i, true);
      return;
    }
  }
};

//-------------------------------------------------------------------------
// 청구처리 확인 => 청구처리가 되었다면 수정 불가
//-------------------------------------------------------------------------
scwin.gr_master_onColumnMove = function (columnIndex, oldColumnIndex) {
  let rowIndex = gr_master.getFocusedRowIndex();
  let colId = gr_master.getColumnID(columnIndex);
  if (rowIndex >= 0) {
    scwin.f_CheckBilgYn(rowIndex, colId, "OnColumnPosChanged");
  }
};

//-------------------------------------------------------------------------
// 입출고 변경에 따른 컴포넌트 컨트롤
//-------------------------------------------------------------------------
scwin.acb_ioClsCd_onChange = function (info) {
  if (acb_ioClsCd.getValue() == "I" || acb_ioClsCd.getValue() == "Z") {
    acb_confirmYn.setValue("");
    acb_confirmYn.setDisabled(true);
    acb_shuttleClsCd.setDisabled(false);
  } else {
    acb_confirmYn.setDisabled(false);
    acb_shuttleClsCd.setDisabled(true);
  }
};

